import asyncio
import anthropic

client = anthropic.Anthropic()

# --- Simulated backend calls ---

async def get_order(order_id: str) -> dict:
    await asyncio.sleep(0.5)
    return {"order_id": order_id, "status": "shipped", "carrier": "FedEx", "tracking": "7489234987"}

async def get_tracking(tracking_number: str, carrier: str) -> dict:
    await asyncio.sleep(0.5)
    return {"tracking_number": tracking_number, "status": "delayed", "eta": "2 days"}

async def get_support_history(user_id: str) -> list:
    await asyncio.sleep(0.5)
    return [{"ticket_id": "T-991", "issue": "late delivery", "resolved": True}]

TOOL_IMPLEMENTATIONS = {
    "get_order": get_order,
    "get_tracking": get_tracking,
    "get_support_history": get_support_history,
}

TOOLS = [
    {
        "name": "get_order",
        "description": "Fetch order details by order ID.",
        "input_schema": {
            "type": "object",
            "properties": {"order_id": {"type": "string"}},
            "required": ["order_id"],
        },
    },
    {
        "name": "get_tracking",
        "description": "Get carrier tracking status for a shipment.",
        "input_schema": {
            "type": "object",
            "properties": {
                "tracking_number": {"type": "string"},
                "carrier": {"type": "string"},
            },
            "required": ["tracking_number", "carrier"],
        },
    },
    {
        "name": "get_support_history",
        "description": "Retrieve a user's past support tickets.",
        "input_schema": {
            "type": "object",
            "properties": {"user_id": {"type": "string"}},
            "required": ["user_id"],
        },
    },
]

async def execute_tool_call(tool_call) -> dict:
    fn = TOOL_IMPLEMENTATIONS[tool_call.name]
    import json
    result = await fn(**tool_call.input)
    return {
        "type": "tool_result",
        "tool_use_id": tool_call.id,
        "content": json.dumps(result),
    }

async def support_agent(user_id: str, order_id: str):
    messages = [
        {
            "role": "user",
            "content": f"User {user_id} is asking: why is order #{order_id} late?",
        }
    ]

    import time
    t0 = time.monotonic()

    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=512,
        tools=TOOLS,
        messages=messages,
    )

    while response.stop_reason == "tool_use":
        tool_calls = [b for b in response.content if b.type == "tool_use"]
        # All three backend calls execute in parallel — total wait ~500ms, not 1500ms
        results = await asyncio.gather(*[execute_tool_call(tc) for tc in tool_calls])

        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": list(results)})

        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=512,
            tools=TOOLS,
            messages=messages,
        )

    elapsed = time.monotonic() - t0
    print(f"Response time: {elapsed:.2f}s")
    return next(b.text for b in response.content if b.type == "text")

print(asyncio.run(support_agent(user_id="U-442", order_id="8821")))
